GameRunningState = class("GameRunningState", GameState)

function GameRunningState:enter()
    self.GameStatus = Define.GameStatus.GameRunning

    self.countDownTime = ChampionShipConfig.gameTime

    for _, player in pairs(PlayerManager:getPlayers()) do
        GamePacketSender:SendPlayerIsAllowWorkout(player.rakssid, false)
        player.property:removeInvincibleState()
    end

    HostApi.sendPlaySound(0, ChampionShipConfig.gameStartMusic)

    GamePacketSender:sendGameStateInfo(self.GameStatus)

    LogUtil.log("GameRunningState:enter")
end

function GameRunningState:update()
    MsgSender.sendTopTips(1, IMessages:msgGameEndTimeHint(self.countDownTime, IMessages.UNIT_SECOND, false))

    self.countDownTime = self.countDownTime - 1

    if self.countDownTime <= 0 or PlayerManager:getReadyPlayerCount() <= 1 then
        GameStateManager:changeState(Define.GameStatus.GameEnd)
    end
end

function GameRunningState:leave()
    --TODO
end

function GameRunningState:onPlayerReady(player)
    player.property:removeInvincibleState()
end

return GameRunningState